$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Řádky starší než tato hodnota budou odstraněny z tabulek connections, connections_source a connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Zadejte počet dní, po které mají být uchovány surové statistiky návštěvnosti PrestaShopu. Příklad: 60 znamená, že modul ponechá posledních 60 dní a starší záznamy z tabulek ps_connections, ps_connections_source a ps_connections_page odstraní. Nenastavujte hodnotu 1, pokud si nejste jistý, že nepotřebujete nedávné statistiky návštěvnosti.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Velikost dávky';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Maximální počet připojení zpracovaných v jedné dávce.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Zadejte, kolik hlavních záznamů připojení se může zpracovat v jedné interní dávce. Menší hodnoty jsou bezpečnější na slabém hostingu, ale vyžadují více spuštění cronu. Větší hodnoty čistí rychleji, ale mohou déle držet databázové zámky. Doporučená počáteční hodnota: 1000 až 5000; zvyšujte až po otestování doby běhu.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Maximální počet dávek na jedno spuštění';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Omezuje množství práce, které může provést jedno spuštění cronu.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Zadejte, kolik dávek může proběhnout během jednoho spuštění cronu. Celkový možný počet odstraněných hlavních záznamů připojení na jedno spuštění je přibližně Velikost dávky krát Maximální počet dávek. Příklad: 5000 a 10 znamená až asi 50000 hlavních záznamů připojení za jedno spuštění cronu. Snižte tuto hodnotu, pokud se obchod během čištění zpomaluje.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Vyčistit ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Vyčistí cache bloku faceted/layered vyhledávání pomocí TRUNCATE TABLE. Tabulka bude v MySQL/MariaDB znovu vytvořena jako prázdná.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Zapněte pouze tehdy, pokud ps_layered_filter_block příliš roste nebo obsahuje zastaralou cache faceted vyhledávání. Nemaže produkty, kategorie ani index vrstvených cen. Po vyčištění může PrestaShop nebo modul faceted vyhledávání tuto cache podle potřeby znovu vytvořit.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agregovat statistiky zdrojů návštěvnosti před odstraněním';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Ukládá denní souhrnné statistiky zdrojů návštěvnosti před odstraněním surových řádků.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Když je zapnuto, modul před odstraněním surových statistik PrestaShopu uloží malý denní souhrn. Uchovává počty jako návštěvy, zobrazení stránek, zdrojovou doménu a UTM hodnoty. Neukládá IP adresy, celé referrer URL ani user-agent řetězce. Vypněte, pokud chcete pouze mazat a nepotřebujete historické souhrny zdrojů.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Počet dnů uchování agregovaných statistik';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Jak dlouho má být uchována malá denní souhrnná tabulka.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Zadejte, kolik dní mají souhrny zdrojů návštěvnosti zůstat v tabulce modulu. Příklad: 730 uchová přibližně dva roky denních souhrnů zdrojů. Toto nastavení ovlivňuje pouze tabulku modulu ps_jooim_dbcleaner_traffic_daily, nikoli původní statistické tabulky PrestaShopu.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Časový limit zastaralého zámku v sekundách';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Ochrana proti souběžnému spuštění dvou čisticích procesů.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2c1824ea38ec688698a26f01a46e6b16'] = 'Zadejte počet sekund, po kterých se nedokončený zámek čištění považuje za opuštěný. Chrání databázi před tím, aby běžela dvě spuštění cronu současně. Doporučená hodnota: 7200. Snižujte ji pouze tehdy, pokud máte jistotu, že cron vždy skončí rychle.';
