$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2806977593fb4c23003cc11306b135d1'] = 'Maximální počet dávek na jedno spuštění';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d31a094a19379b58b63b51ef0f9d9362'] = 'Omezuje množství práce, které může provést jedno spuštění cronu.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_e221a5a91ea62a43adc5bb15614eb578'] = 'Zadejte, kolik dávek může proběhnout během jednoho spuštění cronu. Celkový možný počet odstraněných hlavních záznamů připojení na jedno spuštění je přibližně Velikost dávky krát Maximální počet dávek. Příklad: 5000 a 10 znamená až asi 50000 hlavních záznamů připojení za jedno spuštění cronu. Snižte tuto hodnotu, pokud se obchod během čištění zpomaluje.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a1a47524ffa9c839887703df1fbe70a3'] = 'Vyčistit ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_924684322fe68e56ef9205e7f480f598'] = 'Vyčistí cache bloku faceted/layered vyhledávání pomocí TRUNCATE TABLE. Tabulka bude v MySQL/MariaDB znovu vytvořena jako prázdná.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Zapněte pouze tehdy, pokud ps_layered_filter_block příliš roste nebo obsahuje zastaralou cache faceted vyhledávání. Nemaže produkty, kategorie ani index vrstvených cen. Po vyčištění může PrestaShop nebo modul faceted vyhledávání tuto cache podle potřeby znovu vytvořit.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agregovat statistiky zdrojů návštěvnosti před odstraněním';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d7e1a0c7e7973ebcde37aa659525105d'] = 'Ukládá denní souhrnné statistiky zdrojů návštěvnosti před odstraněním surových řádků.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ae729759e10d7a626a8622321932a1f4'] = 'Když je zapnuto, modul před odstraněním surových statistik PrestaShopu uloží malý denní souhrn. Uchovává počty jako návštěvy, zobrazení stránek, zdrojovou doménu a UTM hodnoty. Neukládá IP adresy, celé referrer URL ani user-agent řetězce. Vypněte, pokud chcete pouze mazat a nepotřebujete historické souhrny zdrojů.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Počet dnů uchování agregovaných statistik';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Jak dlouho má být uchována malá denní souhrnná tabulka.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Zadejte, kolik dní mají souhrny zdrojů návštěvnosti zůstat v tabulce modulu. Příklad: 730 uchová přibližně dva roky denních souhrnů zdrojů. Toto nastavení ovlivňuje pouze tabulku modulu ps_jooim_dbcleaner_traffic_daily, nikoli původní statistické tabulky PrestaShopu.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Časový limit zastaralého zámku v sekundách';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Ochrana proti souběžnému spuštění dvou čisticích procesů.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Zadejte počet sekund, po kterých se nedokončený zámek čištění považuje za opuštěný. Chrání databázi před tím, aby běžela dvě spuštění cronu současně. Doporučená hodnota: 7200. Snižujte ji pouze tehdy, pokud máte jistotu, že cron vždy skončí rychle.';
